import{_ as t,o,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Agent Tools","description":"","frontmatter":{},"headers":[],"relativePath":"features/agent-tools.md","filePath":"features/agent-tools.md"}'),r={name:"features/agent-tools.md"};function n(l,e,d,s,c,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="agent-tools" tabindex="-1">Agent Tools <a class="header-anchor" href="#agent-tools" aria-label="Permalink to &quot;Agent Tools&quot;">​</a></h1><p>Lyra Code&#39;s Agent tools transform your Android device into a capable AI workstation. All tools operate with <strong>user review and approval</strong> for safety.</p><h2 id="file-operations" tabindex="-1">File Operations <a class="header-anchor" href="#file-operations" aria-label="Permalink to &quot;File Operations&quot;">​</a></h2><p>The Agent can read, write, and manage files within the workspace:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th></tr></thead><tbody><tr><td><code>read_file</code></td><td>Read text files up to 1 MB</td></tr><tr><td><code>write_file</code></td><td>Create or overwrite files with line-by-line content</td></tr><tr><td><code>append_file</code></td><td>Append content to existing files</td></tr><tr><td><code>delete_file_or_folder</code></td><td>Remove files or empty directories</td></tr><tr><td><code>rename_move</code></td><td>Rename or move files within the workspace</td></tr><tr><td><code>create_folder</code></td><td>Create new directories</td></tr><tr><td><code>search_files</code></td><td>Search by filename, extension, or path</td></tr><tr><td><code>get_file_info</code></td><td>Retrieve file metadata</td></tr></tbody></table><h2 id="native-downloads" tabindex="-1">Native Downloads <a class="header-anchor" href="#native-downloads" aria-label="Permalink to &quot;Native Downloads&quot;">​</a></h2><p>Download files directly from HTTP/HTTPS URLs:</p><ul><li>Save to workspace or Android shared storage (Download folder)</li><li>Custom request headers</li><li>Configurable timeouts</li><li>Optional SHA-256 integrity verification</li><li>Redirect following</li></ul><div class="tip custom-block"><p class="custom-block-title">Preferred Method</p><p>Native downloads are the primary method for fetching files. Termux <code>curl</code> / <code>wget</code> are retained only as fallback options.</p></div><h2 id="command-execution" tabindex="-1">Command Execution <a class="header-anchor" href="#command-execution" aria-label="Permalink to &quot;Command Execution&quot;">​</a></h2><p>Execute shell commands through Termux <code>RunCommandService</code>:</p><ul><li>Full <code>stdout</code> / <code>stderr</code> feedback</li><li>Configurable timeouts (up to 600 seconds)</li><li>Multi-line command support</li><li>Exit code reporting</li></ul><h2 id="web-tools" tabindex="-1">Web Tools <a class="header-anchor" href="#web-tools" aria-label="Permalink to &quot;Web Tools&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th></tr></thead><tbody><tr><td><code>web_search</code></td><td>Search the web and get ranked results</td></tr><tr><td><code>read_web_page</code></td><td>Read and parse web page content</td></tr><tr><td><code>mark_web_sources</code></td><td>Annotate sources used in AI responses</td></tr></tbody></table><h2 id="planning-review" tabindex="-1">Planning &amp; Review <a class="header-anchor" href="#planning-review" aria-label="Permalink to &quot;Planning &amp; Review&quot;">​</a></h2><ul><li><strong>TODO lists</strong> — Multi-step task planning with real-time progress updates</li><li><strong>File change review</strong> — Diff visualization for every file modification</li><li><strong>Tool approval</strong> — Review and approve each tool call before execution</li><li><strong>Per-session bypass</strong> — Optionally skip confirmations within a trusted session</li></ul><h2 id="context-awareness" tabindex="-1">Context Awareness <a class="header-anchor" href="#context-awareness" aria-label="Permalink to &quot;Context Awareness&quot;">​</a></h2><p>The Agent has awareness of:</p><ul><li><strong>Time</strong> — Current local time, timezone, and timestamps</li><li><strong>Location</strong> — Device location (with permission) for location-aware queries</li><li><strong>Device hardware</strong> — Full diagnostics and system information</li></ul><h2 id="configuration-management" tabindex="-1">Configuration Management <a class="header-anchor" href="#configuration-management" aria-label="Permalink to &quot;Configuration Management&quot;">​</a></h2><p>The Agent can manage its own configuration through natural language:</p><ul><li>Add, modify, enable, or disable MCP servers</li><li>Configure SSH connections</li><li>Manage WebDAV storage</li><li>Import and manage Skills packages</li><li>Toggle Agent tools on/off</li></ul>',22)])])}const m=t(r,[["render",n]]);export{p as __pageData,m as default};
